const int base_cuda_threads = 256;

using benchmark_clock = std::chrono::steady_clock;

template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__device__ __forceinline__ Element bench_block_kernel(Element* data, size_t base_idx) {
  Element sum = 0;

#ifdef BASELINE_IMPL
  Element f = data[base_idx];

  #pragma unroll
  for (size_t i = 0; i < static_chunk_size; i++) {
    Element t = data[base_idx + i];
    #pragma unroll
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }
#else
  Element f[8];
  #pragma unroll
  for (int idx = 0; idx < 8; ++idx) {
    f[idx] = data[base_idx + idx];
  }

  #pragma unroll
  for (size_t i = 0; i < static_chunk_size; i++) {
    Element t[8];
    #pragma unroll
    for (int idx = 0; idx < 8; ++idx) {
      t[idx] = data[base_idx + i];
    }
    #pragma unroll
    for (size_t j = 0; j < compute_iterations / 8; j++) {
      #pragma unroll
      for (int idx = 0; idx < 8; ++idx) {
        t[idx] = t[idx] * t[idx] + f[idx];
      }
    }
    constexpr size_t rem = compute_iterations % 8;
    if constexpr (rem > 0) t[0] = t[0] * t[0] + f[0];
    if constexpr (rem > 1) t[1] = t[1] * t[1] + f[1];
    if constexpr (rem > 2) t[2] = t[2] * t[2] + f[2];
    if constexpr (rem > 3) t[3] = t[3] * t[3] + f[3];
    if constexpr (rem > 4) t[4] = t[4] * t[4] + f[4];
    if constexpr (rem > 5) t[5] = t[5] * t[5] + f[5];
    if constexpr (rem > 6) t[6] = t[6] * t[6] + f[6];
    sum += t[0] + t[1] + t[2] + t[3] + t[4] + t[5] + t[6] + t[7];
  }
#endif
  return sum;
}

template <typename Element, size_t compute_iterations, size_t static_chunk_size>
__global__ void bench_kernel(Element* data, size_t len, Element* result) {
  using block_sum_t = Element;
  __shared__ block_sum_t shared_sum[32];

  size_t idx = blockIdx.x * blockDim.x + threadIdx.x;
  size_t total_threads = gridDim.x * blockDim.x;
  block_sum_t local_sum = 0;

  for (size_t base = idx * static_chunk_size; base < len; base += total_threads * static_chunk_size) {
    if (base + static_chunk_size <= len) {
      local_sum += bench_block_kernel<Element, compute_iterations, static_chunk_size>(data, base);
    }
  }

  shared_sum[threadIdx.x % 32] = local_sum;
  __syncthreads();

  // Reduce within warp
  if ((threadIdx.x % 32) < 16) shared_sum[threadIdx.x % 32] += shared_sum[(threadIdx.x % 32) + 16];
  __syncwarp();
  if ((threadIdx.x % 32) < 8) shared_sum[threadIdx.x % 32] += shared_sum[(threadIdx.x % 32) + 8];
  __syncwarp();
  if ((threadIdx.x % 32) < 4) shared_sum[threadIdx.x % 32] += shared_sum[(threadIdx.x % 32) + 4];
  __syncwarp();
  if ((threadIdx.x % 32) < 2) shared_sum[threadIdx.x % 32] += shared_sum[(threadIdx.x % 32) + 2];
  __syncwarp();
  if ((threadIdx.x % 32) < 1) shared_sum[threadIdx.x % 32] += shared_sum[(threadIdx.x % 32) + 1];
  __syncwarp();

  // Now reduce across warps within block
  if (threadIdx.x % 32 == 0) {
    atomicAdd(result, shared_sum[threadIdx.x % 32]);
  }
}

template <typename Element, size_t compute_iterations>
size_t bench_cuda(size_t len, const Element seed1, const Element seed2, Element* src_d) {
  constexpr size_t static_chunk_size = 4096;

  Element* result_d;
  Element zero = 0;
  cudaMalloc(&result_d, sizeof(Element));
  cudaMemcpy(result_d, &zero, sizeof(Element), cudaMemcpyHostToDevice);

  int blocks = (len / static_chunk_size + base_cuda_threads - 1) / base_cuda_threads;

  bench_kernel<Element, compute_iterations, static_chunk_size><<<blocks, base_cuda_threads>>>(src_d, len, result_d);
  cudaDeviceSynchronize();

  Element sum = 0;
  cudaMemcpy(&sum, result_d, sizeof(Element), cudaMemcpyDeviceToHost);
  cudaFree(result_d);

  cudaMemcpy(src_d, &sum, sizeof(Element), cudaMemcpyHostToDevice);

  return len;
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = size / sizeof(double);
  auto timer_start = benchmark_clock::now();

  double* d_ptr;
  cudaMalloc(&d_ptr, size);
  cudaMemset(d_ptr, 0, size);

  bench_cuda<double, 16>(num_elements, 1., -1., d_ptr);

  cudaFree(d_ptr);

  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count();
}

template <typename Op>
auto measure_operation(Op op) {
  auto timer_start = benchmark_clock::now();
  op();
  auto timer_duration = benchmark_clock::now() - timer_start;
  return std::chrono::duration_cast<std::chrono::microseconds>(timer_duration).count() / 1000.;
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  return *std::min_element(std::begin(measurements), std::end(measurements));
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements            
            * compute_iterations_ 
            * 2                   
            * 1                   
        + total_elements - 1;     
    return computations;
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, compute_iterations};

  float* c_as_float;
  cudaMalloc(&c_as_float, cs.element_count<float>() * sizeof(float));
  cudaMemset(c_as_float, 0, cs.element_count<float>() * sizeof(float));

  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f, c_as_float);
    });
  });

  double* c_as_double;
  cudaMalloc(&c_as_double, cs.element_count<double>() * sizeof(double));
  cudaMemset(c_as_double, 0, cs.element_count<double>() * sizeof(double));

  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<double, compute_iterations>(cs.element_count<double>(), 1., -1., c_as_double);
    });
  });

  int* c_as_int;
  cudaMalloc(&c_as_int, cs.element_count<int>() * sizeof(int));
  cudaMemset(c_as_int, 0, cs.element_count<int>() * sizeof(int));

  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench_cuda<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;

  cudaFree(c_as_float);
  cudaFree(c_as_double);
  cudaFree(c_as_int);
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

void mixbenchCPU(void* c, size_t size) {
  // Zero memory on device
  cudaMemset(c, 0, size);

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(c, size);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(c, size);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;
}

#include <cstring>
#include <memory>
constexpr auto DEF_VECTOR_SIZE_PER_THREAD = 4 * 1024 * 1024;

using ArgParams = struct { unsigned int vecwidth; };

bool argument_parsing(int argc, char* argv[], ArgParams* output) {
  int arg_count = 0;
  for (int i = 1; i < argc; i++) {
    if ((strcmp(argv[i], "-h") == 0) || (strcmp(argv[i], "--help") == 0)) {
      return false;
    } else {
      unsigned long value = strtoul(argv[i], NULL, 10);
      switch (arg_count) {
        case 0:
          output->vecwidth = value;
          arg_count++;
          break;
        default:
          return false;
      }
    }
  }
  return true;
}

int main(int argc, char* argv[]) {
  std::cout << "mixbench-cpu (" << VERSION_INFO << ")" << std::endl;

  int device_count = 0;
  cudaGetDeviceCount(&device_count);
  if (device_count == 0) {
    std::cerr << "No CUDA devices found." << std::endl;
    return 1;
  }

  ArgParams args{static_cast<unsigned int>(device_count * DEF_VECTOR_SIZE_PER_THREAD / (1024 * 1024))};

  if (!argument_parsing(argc, argv, &args)) {
    std::cout << "Usage: mixbench-cpu [options] [array size(1024^2)]"
              << std::endl
              << std::endl
              << "Options:" << std::endl
              << "  -h or --help              Show this message" << std::endl;

    exit(1);
  }

  std::cout << "Use \"-h\" argument to see available options" << std::endl;

  const size_t VEC_WIDTH = 1024 * 1024 * args.vecwidth;

  void* c;

  cudaMalloc(&c, VEC_WIDTH * sizeof(double));

  std::cout << "Working memory size: " << args.vecwidth * sizeof(double) << "MB"
            << std::endl;
  std::cout << "Total devices: " << device_count << std::endl;

  mixbenchCPU(c, VEC_WIDTH * sizeof(double));

  cudaFree(c);
  return 0;
}
